def frequency_lists(lists):
    """
    This function takes a list of lists and returns a dictionary where each key is a unique sublist from the input,
    and the value is the number of times that sublist appears in the input.

    :param lists: List of lists to analyze
    :return: Dictionary with sublists as keys and their frequencies as values
    """
    frequency_dict = {}
    for lst in lists:
        for item in lst:
            if isinstance(item, list):
                key = tuple(item)
                if key in frequency_dict:
                    frequency_dict[key] += 1
                else:
                    frequency_dict[key] = 1
    return frequency_dict
```

