def remove_Occ(s, ch):
    if len(s) < 2 or s[0] != s[-1]:
        return s

    start = 0
    end = len(s)

    while True:
        try:
            index = s.index(ch, start + 1)
            start = index
        except ValueError:
            break

        try:
            index = s.rindex(ch, 0, end - 1)
            end = index
        except ValueError:
            return s

    return s[:start] + s[end+1:]
```

