import heapq

def func(lists, k):
    # Combine all lists into one list
    combined_list = []
    for lst in lists:
        combined_list.extend(lst)

    # Use heap queue algorithm to find top k elements by their frequency
    freq_heap = []
    for num in combined_list:
        if len(freq_heap) < k:
            heapq.heappush(freq_heap, (num, 1))
        else:
            current_freq = freq_heap[0][1]
            if current_freq == num:
                continue
            elif current_freq > num:
                heapq.heapreplace(freq_heap, (num, num + 1))
    # Extract the top k elements from the heap
    return [heapq.heappop(freq_heap)[0] for _ in range(k)]
```

