def eulerian_num(n, m):
    if n == 0 and m == 1:
        return 1
    elif n < 0 or m < 0:
        raise ValueError("n and m must be non-negative integers.")

    def helper(a, b):
        if a == 0:
            return 1
        else:
            return (a * helper(a - 1, b)) % (10**9 + 7)

    mod = 10**9 + 7

    # Calculate the Euler's totient function for m
    phi_m = 1
    for i in range(2, int(m**0.5) + 1):
        if m % i == 0:
            while m % i == 0:
                m //= i
                phi_m *= (i - 1)

    # Calculate the Euler's totient function for n
    phi_n = helper(n, m)

    return (phi_n * helper(phi_m, m)) % mod
```

