def max_difference(tuples_list):
    if not tuples_list or len(tuples_list) < 2:
        return None

    min_val, max_diff = float('inf'), -float('inf')

    for tup in tuples_list:
        current_val = tup[1] - tup[0]
        if current_val > max_diff:
            max_diff = current_val
        elif current_val < min_val:
            min_val = current_val

    return max(max_diff, 0)
