def compute_Last_Digit(a, b):
    # Calculate the greatest common divisor (GCD) of a and b
    gcd = 1
    for i in range(2, min(a, b) + 1):
        if a % i == 0 and b % i == 0:
            gcd *= i

    # Compute the last digit of the factorial of the GCD
    return (a * b) // gcd % 10
```

