def rearange_string(s):
    char_count = {}

    # Count occurrences of each character
    for char in s:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    result = []
    for i in range(256):  # Assuming ASCII characters only
        count = char_count.get(chr(i), 0)

        while count > 0:
            if len(result) < 2 or result[-1] != chr(i):
                result.append(chr(i))
                count -= 1
            else:
                break

    return ''.join(result)
```

